// Some portions generated by Codex
package org.eclipse.rdf4j.sail.lmdb;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertFalse;
import static org.junit.jupiter.api.Assertions.assertTrue;

import org.eclipse.rdf4j.model.base.CoreDatatype;
import org.eclipse.rdf4j.model.impl.SimpleValueFactory;
import org.eclipse.rdf4j.model.vocabulary.XSD;
import org.junit.jupiter.api.Test;

class PredicateObjectGuaranteeTest {

	private static final SimpleValueFactory VF = SimpleValueFactory.getInstance();

	@Test
	void classifiesCanonicalIntegerLiteralsAsOverlappingFacts() {
		PredicateObjectGuarantee zero = PredicateObjectGuarantee.classify(VF.createLiteral("0", XSD.INTEGER));
		assertHas(zero, PredicateObjectGuarantee.Fact.LITERAL);
		assertHas(zero, PredicateObjectGuarantee.Fact.LITERAL_WITHOUT_LANGUAGE);
		assertHas(zero, PredicateObjectGuarantee.Fact.NUMBER);
		assertHas(zero, PredicateObjectGuarantee.Fact.CANONICAL_INTEGER);
		assertHasDatatype(zero, CoreDatatype.XSD.INTEGER);

		assertHas(PredicateObjectGuarantee.classify(VF.createLiteral("7", XSD.INT)),
				PredicateObjectGuarantee.Fact.CANONICAL_INTEGER);
		assertHas(PredicateObjectGuarantee.classify(VF.createLiteral("-7", XSD.INTEGER)),
				PredicateObjectGuarantee.Fact.CANONICAL_INTEGER);
	}

	@Test
	void classifiesValidNonCanonicalIntegerAndNonIntegerNumericLiteralsAsNumber() {
		PredicateObjectGuarantee leadingZero = PredicateObjectGuarantee.classify(VF.createLiteral("007", XSD.INT));
		assertHas(leadingZero, PredicateObjectGuarantee.Fact.NUMBER);
		assertFalse(leadingZero.has(PredicateObjectGuarantee.Fact.CANONICAL_INTEGER));
		assertHasDatatype(leadingZero, CoreDatatype.XSD.INT);

		PredicateObjectGuarantee positive = PredicateObjectGuarantee.classify(VF.createLiteral("+7", XSD.INTEGER));
		assertHas(positive, PredicateObjectGuarantee.Fact.NUMBER);
		assertFalse(positive.has(PredicateObjectGuarantee.Fact.CANONICAL_INTEGER));
		assertHasDatatype(positive, CoreDatatype.XSD.INTEGER);

		PredicateObjectGuarantee decimal = PredicateObjectGuarantee.classify(VF.createLiteral("1.0", XSD.DECIMAL));
		assertHas(decimal, PredicateObjectGuarantee.Fact.NUMBER);
		assertFalse(decimal.has(PredicateObjectGuarantee.Fact.CANONICAL_INTEGER));
		assertHasDatatype(decimal, CoreDatatype.XSD.DECIMAL);

		PredicateObjectGuarantee doubleValue = PredicateObjectGuarantee.classify(VF.createLiteral("1.0E0", XSD.DOUBLE));
		assertHas(doubleValue, PredicateObjectGuarantee.Fact.NUMBER);
		assertFalse(doubleValue.has(PredicateObjectGuarantee.Fact.CANONICAL_INTEGER));
		assertHasDatatype(doubleValue, CoreDatatype.XSD.DOUBLE);
	}

	@Test
	void classifiesInvalidNumericAndNonNumericValuesWithoutNumericFacts() {
		PredicateObjectGuarantee invalidInt = PredicateObjectGuarantee
				.classify(VF.createLiteral("not-an-int", XSD.INT));
		assertHas(invalidInt, PredicateObjectGuarantee.Fact.LITERAL);
		assertHasDatatype(invalidInt, CoreDatatype.XSD.INT);
		assertFalse(invalidInt.has(PredicateObjectGuarantee.Fact.NUMBER));
		assertFalse(invalidInt.has(PredicateObjectGuarantee.Fact.CANONICAL_INTEGER));

		PredicateObjectGuarantee plain = PredicateObjectGuarantee.classify(VF.createLiteral("plain"));
		assertHas(plain, PredicateObjectGuarantee.Fact.LITERAL);
		assertHas(plain, PredicateObjectGuarantee.Fact.LITERAL_WITHOUT_LANGUAGE);
		assertHasDatatype(plain, CoreDatatype.XSD.STRING);
		assertFalse(plain.has(PredicateObjectGuarantee.Fact.NUMBER));
	}

	@Test
	void classifiesResourceAndLanguageFacts() {
		PredicateObjectGuarantee iri = PredicateObjectGuarantee.classify(VF.createIRI("http://example.com/value"));
		assertHas(iri, PredicateObjectGuarantee.Fact.IRI);
		assertFalse(iri.has(PredicateObjectGuarantee.Fact.LITERAL));

		PredicateObjectGuarantee bnode = PredicateObjectGuarantee.classify(VF.createBNode());
		assertHas(bnode, PredicateObjectGuarantee.Fact.BNODE);
		assertFalse(bnode.has(PredicateObjectGuarantee.Fact.IRI));

		PredicateObjectGuarantee langLiteral = PredicateObjectGuarantee.classify(VF.createLiteral("text", "en"));
		assertHas(langLiteral, PredicateObjectGuarantee.Fact.LITERAL);
		assertHas(langLiteral, PredicateObjectGuarantee.Fact.LITERAL_WITH_LANGUAGE);
		assertFalse(langLiteral.has(PredicateObjectGuarantee.Fact.LITERAL_WITHOUT_LANGUAGE));
	}

	@Test
	void classifiesDateTimezoneFacts() {
		PredicateObjectGuarantee utc = PredicateObjectGuarantee.classify(VF.createLiteral("2024-01-01Z", XSD.DATE));
		assertHas(utc, PredicateObjectGuarantee.Fact.DATE_UTC);
		assertFalse(utc.has(PredicateObjectGuarantee.Fact.DATE_WITHOUT_TIMEZONE));
		assertHasDatatype(utc, CoreDatatype.XSD.DATE);

		PredicateObjectGuarantee withoutTimezone = PredicateObjectGuarantee
				.classify(VF.createLiteral("2024-01-01", XSD.DATE));
		assertHas(withoutTimezone, PredicateObjectGuarantee.Fact.DATE_WITHOUT_TIMEZONE);
		assertFalse(withoutTimezone.has(PredicateObjectGuarantee.Fact.DATE_UTC));
		assertHasDatatype(withoutTimezone, CoreDatatype.XSD.DATE);
	}

	@Test
	void classifiesEveryXsdDatatypeFact() {
		for (CoreDatatype.XSD datatype : CoreDatatype.XSD.values()) {
			PredicateObjectGuarantee guarantee = PredicateObjectGuarantee
					.classify(VF.createLiteral("value", datatype.getIri()));
			assertHasDatatype(guarantee, datatype);
		}
	}

	@Test
	void combinesGuaranteesByKeepingOnlySharedFacts() {
		PredicateObjectGuarantee canonicalInt = PredicateObjectGuarantee.classify(VF.createLiteral("7", XSD.INT));
		PredicateObjectGuarantee decimal = PredicateObjectGuarantee.classify(VF.createLiteral("7.0", XSD.DECIMAL));
		PredicateObjectGuarantee mixedNumeric = canonicalInt.combine(decimal);
		assertHas(mixedNumeric, PredicateObjectGuarantee.Fact.LITERAL);
		assertHas(mixedNumeric, PredicateObjectGuarantee.Fact.LITERAL_WITHOUT_LANGUAGE);
		assertHas(mixedNumeric, PredicateObjectGuarantee.Fact.NUMBER);
		assertFalse(mixedNumeric.has(PredicateObjectGuarantee.Fact.CANONICAL_INTEGER));
		assertFalse(mixedNumeric.hasDatatype(CoreDatatype.XSD.INT));
		assertFalse(mixedNumeric.hasDatatype(CoreDatatype.XSD.DECIMAL));

		PredicateObjectGuarantee mixedValueKinds = canonicalInt
				.combine(PredicateObjectGuarantee.classify(VF.createIRI("http://example.com/value")));
		assertEquals(PredicateObjectGuarantee.NONE, mixedValueKinds);
	}

	private static void assertHas(PredicateObjectGuarantee guarantee, PredicateObjectGuarantee.Fact fact) {
		assertTrue(guarantee.has(fact), () -> "Expected " + guarantee + " to contain " + fact);
	}

	private static void assertHasDatatype(PredicateObjectGuarantee guarantee, CoreDatatype.XSD datatype) {
		assertTrue(guarantee.hasDatatype(datatype), () -> "Expected " + guarantee + " to contain " + datatype);
	}
}
